type PageSpec = {
	name: string;
	path: (ids: { nodeId: string; projectId: string }) => string;
};

const PAGES = [
	{ path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}`, name: 'dashboard' },
	{ path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}/beads`, name: 'beads' },
