 27		let promptText = $state('');
 28		let tier = $state(2);
 29		let submitting = $state(false);
 30		let approving = $state(false);
 31		let pendingBead = $state<OperatorPromptBead | null>(null);
 32		let alertMessage = $state('');
 33		let recent = $state<OperatorPromptBead[]>([]);
 34		let liveStatus = $state<Map<string, string>>(new Map());
