 36		function newIdempotencyKey(): string {
 37			if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
 38				return crypto.randomUUID();
 39			}
 40			return `op-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
 41		}
