 43		async function gqlRequest<T>(query: string, variables: Record<string, unknown>): Promise<T> {
 44			const token = await getCsrfToken();
 45			const resp = await fetch('/graphql', {
 46				method: 'POST',
 47				credentials: 'same-origin',
 48				headers: {
 49					'Content-Type': 'application/json',
 50					'X-CSRF-Token': token
 51				},
 52				body: JSON.stringify({ query, variables })
 53			});
 54			const body = (await resp.json()) as {
 55				data?: T;
 56				errors?: Array<{ message: string }>;
 57			};
 58			if (body.errors && body.errors.length > 0) {
 59				throw new Error(body.errors.map((e) => e.message).join('; '));
 60			}
 61			if (!body.data) {
 62				throw new Error(`graphql request failed: ${resp.status}`);
 63			}
 64			return body.data;
 65		}
