 67		async function loadRecent() {
 68			try {
 69				const data = await gqlRequest<RecentOperatorPromptsResult>(RECENT_OPERATOR_PROMPTS_QUERY, {
 70					projectID: projectId
 71				});
 72				recent = data.beadsByProject.edges
 73					.map((e) => e.node)
 74					.sort((a, b) => {
 75						const aTime = Date.parse(a.createdAt ?? a.updatedAt);
 76						const bTime = Date.parse(b.createdAt ?? b.updatedAt);
 77						if (Number.isNaN(aTime) || Number.isNaN(bTime)) {
 78							return (b.updatedAt ?? '').localeCompare(a.updatedAt ?? '');
 79						}
 80						return bTime - aTime;
 81					})
 82					.slice(0, 10);
 83			} catch (err) {
 84				alertMessage = `Could not load recent prompts. ${errorText(err)}`;
 85			}
 86		}
 87	
 88		async function handleSubmit(event: SubmitEvent) {
 89			event.preventDefault();
 90			alertMessage = '';
 91			const trimmed = promptText.trim();
 92			if (!trimmed) {
 93				alertMessage = 'Prompt cannot be empty.';
 94				return;
 95			}
 96			submitting = true;
 97			try {
 98				const data = await gqlRequest<OperatorPromptSubmitResult>(OPERATOR_PROMPT_SUBMIT_MUTATION, {
 99					input: {
100						prompt: trimmed,
101						tier,
102						idempotencyKey: newIdempotencyKey(),
103						autoApprove: false
104					}
105				});
106				pendingBead = data.operatorPromptSubmit.bead;
107				await loadRecent();
108			} catch (err) {
109				alertMessage = errorText(err);
110			} finally {
111				submitting = false;
112			}
113		}
114	
115		async function handleApprove() {
116			if (!pendingBead) return;
117			approving = true;
118			alertMessage = '';
119			try {
120				const data = await gqlRequest<OperatorPromptApproveResult>(OPERATOR_PROMPT_APPROVE_MUTATION, {
121					id: pendingBead.id
122				});
123				pendingBead = data.operatorPromptApprove.bead;
124				promptText = '';
125				pendingBead = null;
126				await loadRecent();
127			} catch (err) {
128				alertMessage = errorText(err);
129			} finally {
130				approving = false;
131			}
132		}
133	
134		async function handleCancel() {
135			if (!pendingBead) return;
136			approving = true;
137			alertMessage = '';
138			try {
139				await gqlRequest<OperatorPromptCancelResult>(OPERATOR_PROMPT_CANCEL_MUTATION, {
140					id: pendingBead.id
141				});
142				pendingBead = null;
143				await loadRecent();
144			} catch (err) {
145				alertMessage = errorText(err);
146			} finally {
147				approving = false;
148			}
149		}
150	
151		function discardPreview() {
152			pendingBead = null;
153		}
154	
155		function beadHref(beadId: string): string {
156			return resolve('/nodes/[nodeId]/projects/[projectId]/beads/[beadId]', {
157				nodeId,
158				projectId,
159				beadId
160			});
161		}
162	
163		function statusOf(bead: OperatorPromptBead): string {
164			return liveStatus.get(bead.id) ?? bead.status;
165		}
166	
167		function statusBadgeClass(status: string): string {
168			switch (status) {
169				case 'proposed':
170					return 'bg-yellow-100 text-yellow-900 dark:bg-yellow-900/30 dark:text-yellow-200';
171				case 'open':
172					return 'bg-green-100 text-green-900 dark:bg-green-900/30 dark:text-green-200';
173				case 'in_progress':
174					return 'bg-blue-100 text-blue-900 dark:bg-blue-900/30 dark:text-blue-200';
175				case 'closed':
176					return 'bg-fg-muted/20 text-fg-muted dark:bg-dark-fg-muted/20 dark:text-dark-fg-muted';
177				case 'cancelled':
178					return 'bg-fg-muted/20 text-fg-muted line-through dark:bg-dark-fg-muted/20 dark:text-dark-fg-muted';
179				default:
180					return 'bg-bg-surface text-fg-ink dark:bg-dark-bg-surface dark:text-dark-fg-ink';
181			}
182		}
183	
184		function errorText(err: unknown): string {
185			if (err instanceof Error) return err.message;
186			if (typeof err === 'string') return err;
187			return 'Unknown error.';
188		}
189	
190		let unsubscribe: (() => void) | null = null;
191		onMount(() => {
192			void loadRecent();
193			unsubscribe = subscribeBeadLifecycle(projectId, (evt) => {
194				if (evt.kind === 'status_changed' && evt.summary) {
195					const match = evt.summary.match(/status changed from \S+ to (\S+)/);
196					if (match) {
197						const next = new Map(liveStatus);
198						next.set(evt.beadID, match[1]);
199						liveStatus = next;
200					}
201				}
202				if (evt.kind === 'created') {
203					void loadRecent();
204				}
205			});
206		});
207		onDestroy(() => {
208			unsubscribe?.();
209		});
210	</script>
