  1	// Playwright e2e for Story-15-6: SvelteKit prompt input + preview + recent-bead
  2	// pane + approve UI + XSS escaping. Runs against the real Go fixture server
  3	// (see playwright.config.ts) so the operatorPromptSubmit/Approve mutations
  4	// hit real resolvers and persist real beads in the temp workspace.
  5	import { expect, test, type APIRequestContext } from '@playwright/test';
