  7	async function getFixtureIds(
  8		request: APIRequestContext
  9	): Promise<{ nodeId: string; projectId: string }> {
 10		const nodeResp = await request.post('/graphql', {
 11			data: { query: '{ nodeInfo { id name } }' }
 12		});
 13		const nodeBody = (await nodeResp.json()) as {
 14			data: { nodeInfo: { id: string; name: string } };
 15		};
 16		const projectsResp = await request.get('/api/projects');
 17		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
 18		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
 19		if (!fixture) {
 20			throw new Error(
 21				`fixture server has no ddx-e2e-* project registered (got: ${projects.map((p) => p.id).join(', ')})`
 22			);
 23		}
 24		return { nodeId: nodeBody.data.nodeInfo.id, projectId: fixture.id };
 25	}
 26	
 27	const OPERATOR_PROMPT_SUBMIT_MUTATION = `mutation Submit($input: OperatorPromptSubmitInput!) {
 28		operatorPromptSubmit(input: $input) {
 29			bead { id }
 30		}
 31	}`;
 32	
 33	async function submitOperatorPrompt(
 34		request: APIRequestContext,
 35		prompt: string,
 36		idempotencyKey: string
 37	): Promise<string> {
 38		const csrfResp = await request.get('/api/csrf-token');
 39		const csrfBody = (await csrfResp.json()) as { token?: string };
 40		const resp = await request.post('/graphql', {
 41			headers: {
 42				'Content-Type': 'application/json',
 43				'X-CSRF-Token': csrfBody.token ?? ''
 44			},
 45			data: {
 46				query: OPERATOR_PROMPT_SUBMIT_MUTATION,
 47				variables: {
 48					input: {
 49						prompt,
 50						idempotencyKey
 51					}
 52				}
 53			}
 54		});
 55		const body = (await resp.json()) as {
 56			data?: {
 57				operatorPromptSubmit?: {
 58					bead?: { id?: string };
 59				};
 60			};
 61			errors?: Array<{ message: string }>;
 62		};
 63		if (body.errors?.length) {
 64			throw new Error(body.errors.map((e) => e.message).join('; '));
 65		}
 66		const beadId = body.data?.operatorPromptSubmit?.bead?.id;
 67		if (!beadId) {
 68			throw new Error('expected operator prompt bead id');
 69		}
 70		return beadId;
 71	}
